script:
# لا تضع أي جمل import هنا، ابدأ الكود مباشرة:

# تعيين تاريخ اليوم إن لم يكن محدداً (Frappe يوفر دالة frappe.utils.today تلقائياً)
if not doc.letter_date:
    doc.letter_date = frappe.utils.today()

# التحقق من وجود القسم المرسِل
if not doc.sender_department:
    frappe.throw('يرجى تحديد القسم المرسل منه')

# التحقق من وجود القسم المستلِم
if not doc.recipient_department:
    frappe.throw('يرجى تحديد القسم المرسل إليه')

# تعيين الحالة الافتراضية
if not doc.status:
    doc.status = 'مسودة'
